import { redirect } from 'next/navigation'
import { Metadata } from 'next'
import { retrieveCustomer, getCustomerProfile } from '@/lib/data/customer'
import { ConsumerSellerDashboard } from '@/components/seller/ConsumerSellerDashboard'

export const metadata: Metadata = {
  title: 'Seller Dashboard | SideDecked',
  description: 'Manage your card listings, track sales, and grow your business on SideDecked marketplace.',
}

export default async function SellPage() {
  const customer = await retrieveCustomer()

  if (!customer) {
    redirect('/user')
  }

  // Check if customer is already a seller (via public profile endpoint)
  const profile = await getCustomerProfile(customer.id).catch(() => null)

  if (!profile?.is_seller) {
    redirect('/sell/upgrade')
  }

  return (
    <main className="min-h-screen bg-background">
      <ConsumerSellerDashboard customer={customer} />
    </main>
  )
}

"use client"
import {
  NavigationItem,
} from "@/components/atoms"
import { useUnreads } from "@talkjs/react"
import { usePathname } from "next/navigation"

const navigationItems = [
  { label: "Orders", href: "/user/orders" },
  { label: "Messages", href: "/user/messages" },
  { label: "Returns", href: "/user/returns" },
  { label: "Addresses", href: "/user/addresses" },
  { label: "Reviews", href: "/user/reviews" },
  { label: "Wishlist", href: "/user/wishlist" },
]

export const UserNavigation = () => {
  const unreads = useUnreads()
  const path = usePathname()

  return (
    <nav
      className="h-min rounded-[14px] overflow-hidden"
      style={{ background: "var(--bg-surface-1, #18162A)", border: "1px solid var(--border-default, #2C2A4A)" }}
    >
      <div className="py-2">
        {navigationItems.map((item) => (
          <NavigationItem
            key={item.label}
            href={item.href}
            active={path === item.href}
            className="relative"
          >
            {item.label}
            {item.label === "Messages" && Boolean(unreads?.length) && (
              <span
                className="absolute top-3 left-24 w-4 h-4 rounded-full flex items-center justify-center text-[10px] font-bold text-white"
                style={{ background: "var(--brand-primary, #8B5CF6)" }}
              >
                {unreads?.length}
              </span>
            )}
          </NavigationItem>
        ))}
      </div>
      <div style={{ borderTop: "1px solid var(--border-default, #2C2A4A)" }} className="py-2">
        <NavigationItem
          href="/user/settings"
          active={path === "/user/settings"}
        >
          Settings
        </NavigationItem>
      </div>
    </nav>
  )
}

